const MINIMAL_GRAPH_URL = new URL('./fixtures/site-capability-graph/minimal-v1.json', import.meta.url);

async function readMinimalGraphFixture() {
  return JSON.parse(await readFile(MINIMAL_GRAPH_URL, 'utf8'));
}

async function createTempArtifactPaths() {
  const dir = await mkdtemp(path.join(os.tmpdir(), 'site-capability-graph-artifacts-'));
  return {
    dir,
    artifactFileName: 'graph-docs-summary.json',
    auditFileName: 'graph-docs-summary.redaction-audit.json',
    artifactPath: path.join(dir, 'graph-docs-summary.json'),
    auditPath: path.join(dir, 'graph-docs-summary.redaction-audit.json'),
  };
}

