test('docs markdown artifact registry consumer dispatches safe summaries without descriptor functions', async () => {
  const { create: createRegistry } = loadGraphDerivedArtifactConsumerRegistryApi();
  const { create: createConsumer } = loadGraphDocsMarkdownArtifactRegistryConsumerApi();
  const graph = await readMinimalGraphFixture();
  const summary = generateGraphDocsSummary(graph);
  const docsArtifact = createGraphDocsMarkdownArtifact(summary);
  const registry = createRegistry();
  const consumerDescriptor = createConsumer({
    consumerId: 'synthetic-docs-markdown-artifact-registry-consumer',
    redactionRequired: true,
  });

  const registeredDescriptor = registerGraphDerivedArtifactConsumer(registry, consumerDescriptor);
  const result = await dispatchGraphDerivedArtifact(registry, docsArtifact);
  const consumerResults = result.consumerResults ?? result.artifactConsumerResults ?? result.results;
  const [consumerResult] = consumerResults;
  const descriptors = listGraphDerivedArtifactConsumerDescriptors(registry);
  const [descriptor] = descriptors;

  assert.equal(registeredDescriptor.consumerId, 'synthetic-docs-markdown-artifact-registry-consumer');
  assert.equal(registeredDescriptor.redactionRequired, true);
  assert.equal(registeredDescriptor.externalTelemetry, false);
  assert.equal(registeredDescriptor.writesArtifacts, false);
  assert.equal(registeredDescriptor.writesLogs, false);
  assert.equal(registeredDescriptor.writesDocs, false);
  assert.equal(registeredDescriptor.writesRepo, false);
  assert.deepEqual(
    registeredDescriptor.artifactFamilies ?? registeredDescriptor.artifactFamilyMatches,
    ['site-capability-graph-docs-markdown'],
  );
  assert.equal(result.artifact?.artifactFamily ?? result.artifactFamily, 'site-capability-graph-docs-markdown');
  assert.equal(Array.isArray(consumerResults), true);
  assert.equal(consumerResults.length, 1);
  assert.equal(consumerResult.accepted ?? true, true);
  assert.equal(consumerResult.consumerId, 'synthetic-docs-markdown-artifact-registry-consumer');
  assert.equal(consumerResult.artifactFamily, 'site-capability-graph-docs-markdown');
  assert.equal(consumerResult.graphVersion, docsArtifact.graphVersion);
  assert.equal(consumerResult.redactionRequired, true);
  assert.equal(consumerResult.externalTelemetryEnabled ?? false, false);
  assert.equal(consumerResult.writesArtifacts ?? false, false);
  assert.equal(consumerResult.writesLogs ?? false, false);
  assert.equal(consumerResult.writesDocs ?? false, false);
  assert.equal(consumerResult.writesRepo ?? false, false);
  assert.equal(consumerResult.writerInvocationEnabled ?? false, false);
  assert.equal(consumerResult.sessionMaterializationEnabled ?? false, false);
  assert.equal(consumerResult.downloaderInvocationEnabled ?? false, false);
  assert.equal(consumerResult.siteAdapterInvocationEnabled ?? false, false);
  assert.equal(descriptor.consumerId, registeredDescriptor.consumerId);
  assert.equal(assertNoFunctionValues(descriptors), true);
  assert.doesNotMatch(
    JSON.stringify({ descriptors, consumerResult }),
    /function|synthetic-secret-value|Authorization|Bearer|cookie|csrf|sessionId|browserProfile/iu,
  );
});

