test('docs-output live consumer dispatch dry-run result dispatches through in-memory registry safely', async () => {
  const {
    create: createDryRunResult,
    assertCompatibility,
  } = loadGraphDocsOutputLiveConsumerDispatchDryRunResultApi();
  const graph = await readMinimalGraphFixture();
  const summary = generateGraphDocsSummary(graph);
  const docsArtifact = createGraphDocsMarkdownArtifact(summary);

  const result = await createGraphDocsOutputLiveConsumerDispatchDryRunResult(createDryRunResult, {
    docsArtifact,
    artifact: docsArtifact,
    dryRunName: 'synthetic-docs-output-live-consumer-dispatch-dry-run-result',
  });
  const item = result.items?.[0] ?? result;
  const dispatchSummary = item.dispatchSummary ?? result.dispatchSummary ?? item.dispatchResult ?? result.dispatchResult;
  const consumerResults =
    item.consumerResults
    ?? result.consumerResults
    ?? item.consumerResultSummaries
    ?? result.consumerResultSummaries
    ?? dispatchSummary?.consumerResults
    ?? dispatchSummary?.artifactConsumerResults
    ?? dispatchSummary?.results;
  const consumerResult = (consumerResults ?? [])
    .find((entry) => entry.consumerId === 'synthetic-docs-output-live-consumer-dispatch-dry-run-consumer')
    ?? (consumerResults ?? [])[0];

  assert.equal(assertCompatibility(result), true);
  assert.match(
    result.queryName,
    /^createGraphDocsOutputLive(?:Layer)?ConsumerDispatchDryRunResult$/u,
  );
  assert.match(
    result.artifactFamily,
    /^site-capability-graph-docs-output-live(?:-layer)?-consumer-dispatch-dry-run-result$/u,
  );
  assert.equal(result.redactionRequired, true);
  assert.equal(item.redactionRequired ?? result.redactionRequired, true);
  assert.equal(item.descriptorOnly ?? result.descriptorOnly, true);
  assert.equal(item.dryRun ?? result.dryRun ?? true, true);
  assert.match(item.dispatchMode ?? result.dispatchMode ?? item.mode ?? 'dry-run', /dry-run|descriptor-only/u);
  assert.equal(Array.isArray(consumerResults), true);
  assert.equal(consumerResults.length >= 1, true);
  assert.equal(
    consumerResult.consumerId ?? consumerResult.subscriberId,
    'site-capability-graph-docs-markdown-artifact-consumer',
  );
  assert.equal(consumerResult.redactionRequired ?? true, true);
  assert.equal(consumerResult.artifactFamily ?? docsArtifact.artifactFamily, docsArtifact.artifactFamily);

  for (const fieldName of [
    'liveConsumerEnabled',
    'liveConsumerDispatchEnabled',
    'runtimeConsumerEnabled',
    'writerEnabled',
    'docsWriteEnabled',
    'repoWriteEnabled',
    'runtimeArtifactWriteEnabled',
    'artifactWriterEnabled',
    'publishEnabled',
    'externalTelemetryEnabled',
    'callbackEnabled',
    'siteAdapterInvocationEnabled',
    'downloaderInvocationEnabled',
    'sessionMaterializationEnabled',
    'taskRunnerEnabled',
  ]) {
    if (Object.hasOwn(item, fieldName)) {
      assert.equal(item[fieldName], false, `${fieldName} must remain false`);
    }
    if (Object.hasOwn(result, fieldName)) {
      assert.equal(result[fieldName], false, `${fieldName} must remain false`);
    }
  }

  assert.equal(assertNoFunctionValues(result), true);
  assert.doesNotMatch(
    JSON.stringify({
      result,
      consumerResult,
    }),
    /synthetic-secret-value|Authorization|Bearer|cookie|csrf|sessionId|browserProfile/iu,
  );
});

