test('docs-output live consumer external dispatch acceptance preflight consumes dry-run safe summary only', async () => {
  const { create: createConsumer } = loadGraphDocsMarkdownArtifactRegistryConsumerApi();
  const {
    create: createDryRunResult,
  } = loadGraphDocsOutputLiveConsumerDispatchDryRunResultApi();
  const {
    create: createPreflight,
    assertCompatibility,
  } = loadGraphDocsOutputLiveConsumerExternalDispatchAcceptancePreflightApi();
  const graph = await readMinimalGraphFixture();
  const summary = generateGraphDocsSummary(graph);
  const docsArtifact = createGraphDocsMarkdownArtifact(summary);
  const docsArtifactConsumer = createConsumer({
    consumerId: 'synthetic-docs-output-live-external-dispatch-acceptance-source-consumer',
  });
  const dryRunResult = await createGraphDocsOutputLiveConsumerDispatchDryRunResult(createDryRunResult, {
    docsArtifact,
    artifact: docsArtifact,
    dryRunName: 'synthetic-docs-output-live-external-dispatch-acceptance-source-dry-run',
  });

  const preflight = await createGraphDocsOutputLiveConsumerExternalDispatchAcceptancePreflight(
    createPreflight,
    dryRunResult,
    {
      preflightName: 'synthetic-docs-output-live-consumer-external-dispatch-acceptance-preflight',
    },
  );
  const sourceSummary =
    preflight.sourceDispatchDryRunResult
    ?? preflight.sourceDispatchDryRunSummary
    ?? preflight.sourceDryRunResult
    ?? preflight.sourceDispatchResult
    ?? preflight.sourceEvidence;

  assert.equal(docsArtifactConsumer.redactionRequired, true);
  assert.equal(docsArtifactConsumer.externalTelemetry, false);
  assert.equal(docsArtifactConsumer.writesArtifacts, false);
  assert.equal(docsArtifactConsumer.writesDocs, false);
  assert.equal(docsArtifactConsumer.writesRepo, false);
  assert.equal(assertCompatibility(preflight), true);
  assert.equal(
    preflight.queryName,
    'createGraphDocsOutputLiveConsumerExternalDispatchAcceptancePreflight',
  );
  assert.equal(preflight.redactionRequired, true);
  assert.equal(preflight.descriptorOnly, true);
  assert.equal(preflight.result, 'blocked');
  assert.equal(preflight.reasonCode, 'graph-runtime-consumer-disabled');
  assert.notStrictEqual(sourceSummary, dryRunResult);
  assert.equal(sourceSummary?.queryName, 'createGraphDocsOutputLiveConsumerDispatchDryRunResult');
  assert.equal(sourceSummary?.redactionRequired, true);
  assert.equal(sourceSummary?.descriptorOnly, true);
  assert.equal(sourceSummary?.result, 'blocked');
  assert.equal(sourceSummary?.reasonCode, 'graph-runtime-consumer-disabled');
  assert.equal(sourceSummary?.consumerResultCount, dryRunResult.consumerResultCount);
  assert.equal(Array.isArray(sourceSummary?.consumerResultSummaries), true);
  assert.equal(sourceSummary.consumerResultSummaries.length, dryRunResult.consumerResultCount);

  for (const fieldName of [
    'externalDispatchEnabled',
    'externalTelemetryEnabled',
    'runtimeDispatchEnabled',
    'writerEnabled',
    'writerInvocationEnabled',
    'writeEnabled',
    'docsWriteEnabled',
    'repoWriteEnabled',
    'runtimeArtifactWriteEnabled',
    'artifactWriterEnabled',
    'artifactWriterInvocationEnabled',
    'registryWriteEnabled',
    'catalogWriteEnabled',
    'publishEnabled',
    'publishTargetEnabled',
    'siteAdapterEnabled',
    'siteAdapterInvocationEnabled',
    'downloaderEnabled',
    'downloaderInvocationEnabled',
    'sessionMaterializationEnabled',
    'sessionViewMaterialized',
    'taskRunnerEnabled',
    'matrixPromotionAllowed',
    'statusPromotionAllowed',
    'verifiedPromotionAllowed',
    'matrixStatusChangeEnabled',
    'statusChangeEnabled',
  ]) {
    if (Object.hasOwn(preflight, fieldName)) {
      assert.equal(preflight[fieldName], false, `${fieldName} must remain false`);
    }
  }

  assert.equal(assertNoFunctionValues(preflight), true);
  const rendered = JSON.stringify(preflight);
  assert.doesNotMatch(rendered, /synthetic-secret-value|Authorization|Bearer|cookie|csrf|sessionId|browserProfile/iu);
  assert.doesNotMatch(rendered, /"externalDispatch"\s*:|"externalTelemetry"\s*:|"telemetrySink"\s*:/u);
  assert.doesNotMatch(rendered, /"callback"\s*:|"consumerCallback"\s*:|"handler"\s*:|"function"\s*:/u);
  assert.doesNotMatch(rendered, /"consumer"\s*:|"registry"\s*:|"siteAdapter"\s*:|"downloader"\s*:/u);
  assert.doesNotMatch(rendered, /"artifactPath"\s*:|"writePath"\s*:|"repoPath"\s*:|"docsOutputPath"\s*:/u);
  assert.doesNotMatch(rendered, /"dispatchPayload"\s*:|"runtimePayload"\s*:|"runtimeDispatch"\s*:/u);
  assert.doesNotMatch(rendered, /"sessionView"\s*:|"taskRunner"\s*:/u);
});

