test('docs-output live consumer artifact-writer invocation evidence writes redacted pair through controlled Layer-owned temp path', async () => {
  const {
    create: createInvocationEvidence,
    assertCompatibility,
  } = loadGraphDocsOutputLiveConsumerArtifactWriterInvocationEvidenceApi();
  const sourcePreflight = await createArtifactWriterInvocationPreflightForInvocationEvidence();
  const graph = await readMinimalGraphFixture();
  const summary = generateGraphDocsSummary(graph);
  const docsArtifact = createGraphDocsMarkdownArtifact(summary);
  const { dir } = await createTempArtifactPaths();
  const placement = createGraphDerivedArtifactPlacement({
    outputDir: dir,
    runId: 'synthetic-run-001',
    artifactFamily: 'site-capability-graph-docs-markdown',
    artifactName: 'graph-docs-markdown',
  });

  const evidence = await createInvocationEvidence({
    artifactWriterInvocationPreflight: sourcePreflight,
    docsArtifact,
    placement,
    mode: 'test-harness-ephemeral',
    testHarness: true,
    ephemeralPlacement: true,
    redactionGuardAccepted: true,
  });
  const artifactJson = await readFile(placement.artifactPath, 'utf8');
  const auditJson = await readFile(placement.auditPath, 'utf8');
  const renderedEvidence = JSON.stringify(evidence);

  assert.equal(assertCompatibility(evidence), true);
  assert.equal(evidence.result, 'invoked');
  assert.equal(evidence.reasonCode, 'controlled-test-harness-ephemeral-artifact-writer-invocation');
  assert.equal(evidence.layerOwnedConsumer, true);
  assert.equal(evidence.testHarnessOnly, true);
  assert.equal(evidence.outputDirKind, 'system-temp-dir');
  assert.equal(evidence.invocationAttempted, true);
  assert.equal(evidence.filesystemWritePerformed, true);
  assert.equal(evidence.auditBeforeArtifact, true);
  assert.equal(evidence.artifactFamilyWritten, 'site-capability-graph-docs-markdown');
  assert.equal(evidence.artifactFileName, placement.artifactFileName);
  assert.equal(evidence.auditFileName, placement.auditFileName);
  assert.equal(evidence.redactionAuditAttachment?.writeOrder, 'audit-before-artifact');
  assert.equal(await pathExists(placement.artifactPath), true);
  assert.equal(await pathExists(placement.auditPath), true);
  assert.equal(assertNoForbiddenPatterns(artifactJson), true);
  assert.equal(assertNoForbiddenPatterns(auditJson), true);
  assert.equal(assertNoForbiddenPatterns(evidence), true);
  assert.equal(assertNoFunctionValues(evidence), true);
  assert.doesNotMatch(
    artifactJson + auditJson + renderedEvidence,
    /Authorization|Bearer|cookie|csrf|sessionId|browserProfile|synthetic-secret-value/iu,
  );
  assert.doesNotMatch(
    renderedEvidence,
    /"artifactPath"\s*:|"auditPath"\s*:|"outputDir"\s*:|"repoPath"\s*:|"docsOutputPath"\s*:/u,
  );
  assert.doesNotMatch(
    renderedEvidence,
    /"siteAdapter"\s*:|"downloader"\s*:|"sessionView"\s*:|"taskRunner"\s*:|"externalTelemetry"\s*:/u,
  );
  for (const fieldName of [
    'repoWriteEnabled',
    'docsWriteEnabled',
    'runtimeLayerDocsWriteEnabled',
    'runtimeArtifactWriteEnabled',
    'externalTelemetryEnabled',
    'externalDispatchEnabled',
    'publishEnabled',
    'taskRunnerEnabled',
    'siteAdapterEnabled',
    'downloaderEnabled',
    'sessionViewEnabled',
    'matrixPromotionAllowed',
    'statusPromotionAllowed',
    'verifiedPromotionAllowed',
  ]) {
    assert.equal(evidence[fieldName], false, `${fieldName} must stay false`);
  }
});

