test('runtime docs artifact write observability invoked controlled temp test-harness source produces observed safe-summary evidence without this API reading/writing artifact/audit files', async () => {
  const {
    create: createObservabilityEvidence,
    assertCompatibility,
  } = loadGraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidenceApi();
  const {
    evidence: sourceEvidence,
    placement,
  } = await createControlledGraphDocsOutputLiveConsumerArtifactWriterInvocationEvidence();
  const beforeArtifactStat = await stat(placement.artifactPath);
  const beforeAuditStat = await stat(placement.auditPath);
  const beforeArtifactJson = await readFile(placement.artifactPath, 'utf8');
  const beforeAuditJson = await readFile(placement.auditPath, 'utf8');

  const evidence = createObservabilityEvidence({
    artifactWriterInvocationEvidence: sourceEvidence,
  });
  const afterArtifactStat = await stat(placement.artifactPath);
  const afterAuditStat = await stat(placement.auditPath);
  const afterArtifactJson = await readFile(placement.artifactPath, 'utf8');
  const afterAuditJson = await readFile(placement.auditPath, 'utf8');
  const sourceSummary = evidence.sourceArtifactWriterInvocationEvidence;
  const renderedEvidence = JSON.stringify(evidence);

  assert.equal(assertCompatibility(evidence), true);
  assert.equal(evidence.result, 'observed');
  assert.equal(evidence.reasonCode, 'controlled-test-harness-ephemeral-artifact-writer-invocation');
  assert.equal(evidence.safeSummaryOnly, true);
  assert.equal(evidence.observabilityEvidenceOnly, true);
  assert.equal(evidence.writerInvokedByThisApi, false);
  assert.equal(evidence.artifactFilesRead, false);
  assert.equal(evidence.auditFilesRead, false);
  assert.equal(evidence.runtimeDispatchPerformed, false);
  assert.equal(evidence.runtimeDocsWritePerformed, false);
  assert.equal(evidence.runtimeArtifactWritePerformed, false);
  assert.equal(evidence.runtimeLogWritePerformed, false);
  assert.equal(evidence.repoWritePerformed, false);
  assert.equal(evidence.docsOutputWritePerformed, false);
  assert.equal(evidence.publishPerformed, false);
  assert.equal(evidence.siteAdapterInvoked, false);
  assert.equal(evidence.downloaderInvoked, false);
  assert.equal(evidence.sessionViewMaterialized, false);
  assert.equal(evidence.taskRunnerInvoked, false);
  assert.equal(evidence.statusPromotionPerformed, false);
  assert.equal(evidence.verifiedPromotionPerformed, false);
  assert.equal(sourceSummary.safeSummaryOnly, true);
  assert.equal(sourceSummary.result, 'invoked');
  assert.equal(sourceSummary.invocationAttempted, true);
  assert.equal(sourceSummary.filesystemWritePerformed, true);
  assert.equal(sourceSummary.auditBeforeArtifact, true);
  assert.equal(sourceSummary.testHarnessOnly, true);
  assert.equal(sourceSummary.outputDirKind, 'system-temp-dir');
  assert.equal(sourceSummary.artifactFamilyWritten, 'site-capability-graph-docs-markdown');
  assert.equal(sourceSummary.redactionAuditAttachment?.writeOrder, 'audit-before-artifact');
  assert.equal(afterArtifactStat.size, beforeArtifactStat.size);
  assert.equal(afterAuditStat.size, beforeAuditStat.size);
  assert.equal(afterArtifactStat.mtimeMs, beforeArtifactStat.mtimeMs);
  assert.equal(afterAuditStat.mtimeMs, beforeAuditStat.mtimeMs);
  assert.equal(afterArtifactJson, beforeArtifactJson);
  assert.equal(afterAuditJson, beforeAuditJson);
  assert.equal(assertNoForbiddenPatterns(evidence), true);
  assert.equal(assertNoFunctionValues(evidence), true);
  assert.doesNotMatch(
    renderedEvidence,
    /"artifactPath"\s*:|"auditPath"\s*:|"outputDir"\s*:|"repoPath"\s*:|"docsOutputPath"\s*:/u,
  );
  assert.doesNotMatch(
    renderedEvidence,
    /"siteAdapter"\s*:|"downloader"\s*:|"sessionView"\s*:|"taskRunner"\s*:|"telemetrySink"\s*:|"logSink"\s*:|"runtimePayload"\s*:/u,
  );
  assert.doesNotMatch(
    renderedEvidence + beforeArtifactJson + beforeAuditJson,
    /Authorization|Bearer|cookie|csrf|sessionId|browserProfile|synthetic-secret-value/iu,
  );
});

