test('runtime docs artifact write observability rejects distinct source aliases', async () => {
  const {
    create: createObservabilityEvidence,
  } = loadGraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidenceApi();
  const {
    evidence: sourceEvidence,
  } = await createControlledGraphDocsOutputLiveConsumerArtifactWriterInvocationEvidence();

  for (const option of [
    {
      artifactWriterInvocationEvidence: { ...sourceEvidence },
      sourceArtifactWriterInvocationEvidence: sourceEvidence,
    },
    {
      artifactWriterInvocationEvidence: sourceEvidence,
      sourceArtifactWriterInvocationEvidence: { ...sourceEvidence },
    },
    {
      artifactWriterInvocationEvidence: sourceEvidence,
      sourceEvidence: { ...sourceEvidence },
    },
    {
      artifactWriterInvocationEvidence: sourceEvidence,
      evidence: { ...sourceEvidence },
    },
  ]) {
    const aliasEvidence =
      option.artifactWriterInvocationEvidence === sourceEvidence
        ? (
          option.sourceArtifactWriterInvocationEvidence
          ?? option.sourceEvidence
          ?? option.evidence
        )
        : option.artifactWriterInvocationEvidence;
    assert.notEqual(aliasEvidence, sourceEvidence);

    const message = await captureRejectedMessage(() => createObservabilityEvidence(option));
    assert.match(message, /distinct source aliases|multiple distinct source aliases/iu);
    assert.doesNotMatch(message, /synthetic-secret-value/u);
  }
});

