test('docs-output live consumer artifact pipeline acceptance boundary rejects unsafe aliases, distinct aliases, and sensitive material', async () => {
  const {
    create: createObservabilityEvidence,
  } = loadGraphDocsOutputLiveConsumerRuntimeDocsArtifactWriteObservabilityEvidenceApi();
  const {
    create: createReadinessGate,
  } = loadGraphDocsOutputLiveConsumerReviewedArtifactPipelineReadinessGateApi();
  const {
    create: createAcceptanceBoundary,
  } = loadGraphDocsOutputLiveConsumerArtifactPipelineAcceptanceBoundaryApi();
  const {
    evidence: sourceArtifactWriterEvidence,
  } = await createControlledGraphDocsOutputLiveConsumerArtifactWriterInvocationEvidence();
  const sourceObservabilityEvidence = createObservabilityEvidence({
    artifactWriterInvocationEvidence: sourceArtifactWriterEvidence,
  });
  const sourceReadinessGate =
    await createGraphDocsOutputLiveConsumerReviewedArtifactPipelineReadinessGate(
      createReadinessGate,
      sourceObservabilityEvidence,
    );

  for (const option of [
    {
      reviewedArtifactPipelineReadinessGate: sourceReadinessGate,
      sourceReviewedArtifactPipelineReadinessGate: {
        runtimePayload: {
          Authorization: 'Bearer synthetic-secret-value',
        },
      },
    },
    {
      reviewedArtifactPipelineReadinessGate: sourceReadinessGate,
      sourceReadinessGate: {
        cookie: 'synthetic-secret-value',
      },
    },
    {
      reviewedArtifactPipelineReadinessGate: sourceReadinessGate,
      sourceGate: {
        sessionView: {
          sessionId: 'synthetic-secret-value',
        },
      },
    },
  ]) {
    const message = await captureRejectedMessage(() => createAcceptanceBoundary(option));
    assert.match(
      message,
      /sourceReviewedArtifactPipelineReadinessGate|sourceReadinessGate|sourceGate|Authorization|cookie|sessionView|sensitive|runtime|distinct source aliases|source aliases/iu,
    );
    assert.doesNotMatch(message, /synthetic-secret-value/u);
  }

  for (const option of [
    {
      reviewedArtifactPipelineReadinessGate: sourceReadinessGate,
      sourceReviewedArtifactPipelineReadinessGate: { ...sourceReadinessGate },
    },
    {
      reviewedArtifactPipelineReadinessGate: sourceReadinessGate,
      readinessGate: { ...sourceReadinessGate },
    },
    {
      reviewedArtifactPipelineReadinessGate: sourceReadinessGate,
      sourceReadinessGate: { ...sourceReadinessGate },
    },
    {
      reviewedArtifactPipelineReadinessGate: sourceReadinessGate,
      sourceGate: { ...sourceReadinessGate },
    },
  ]) {
    const message = await captureRejectedMessage(() => createAcceptanceBoundary(option));
    assert.match(message, /distinct source aliases|source aliases must reference the same descriptor object|multiple distinct source aliases/iu);
    assert.doesNotMatch(message, /synthetic-secret-value/u);
  }

  for (const fieldName of [
    'Authorization',
    'authorizationHeader',
    'cookie',
    'csrf',
    'csrfToken',
    'token',
    'sessionId',
    'browserProfile',
    'credential',
    'credentials',
    'syntheticSensitiveMaterial',
  ]) {
    const message = await captureRejectedMessage(
      () => createGraphDocsOutputLiveConsumerArtifactPipelineAcceptanceBoundary(
        createAcceptanceBoundary,
        sourceReadinessGate,
        {
          [fieldName]: 'synthetic-secret-value',
        },
      ),
    );
    assert.match(message, /forbidden|Forbidden sensitive pattern|sensitive|descriptor-only|runtime|acceptance|boundary/iu, fieldName);
    assert.match(message, new RegExp(fieldName, 'iu'), fieldName);
    assert.doesNotMatch(message, /synthetic-secret-value/u, fieldName);
  }
});

