test('graph-derived artifact consumer dispatch redaction audit gate returns safe consumer summaries', async () => {
  const { create: createRegistry } = loadGraphDerivedArtifactConsumerRegistryApi();
  const { create: createConsumer } = loadGraphDocsMarkdownArtifactRegistryConsumerApi();
  const {
    dispatch: dispatchWithRedactionAuditGate,
    assertCompatibility,
  } = loadGraphDerivedArtifactConsumerDispatchRedactionGateApi();
  const graph = await readMinimalGraphFixture();
  const summary = generateGraphDocsSummary(graph);
  const docsArtifact = createGraphDocsMarkdownArtifact(summary);
  const prepared = prepareGraphDerivedArtifactWrite(docsArtifact);
  const registry = createRegistry();
  const consumerDescriptor = createConsumer({
    consumerId: 'synthetic-docs-markdown-redaction-audit-gate-consumer',
  });

  registerGraphDerivedArtifactConsumer(registry, consumerDescriptor);
  const descriptors = listGraphDerivedArtifactConsumerDescriptors(registry);
  const gateResult = await dispatchWithRedactionAuditGate({
    consumerRegistry: registry,
    artifact: docsArtifact,
    redactionAuditAttachment: prepared.redactionAuditAttachment,
  });
  const [consumerResult] = gateResult.consumerResults;

  assert.equal(assertCompatibility(gateResult), true);
  assert.equal(gateResult.schemaVersion, 1);
  assert.equal(gateResult.dispatchMode, 'in-memory-consumer-registry');
  assert.equal(gateResult.artifactFamily, 'site-capability-graph-docs-markdown');
  assert.equal(gateResult.queryName, docsArtifact.queryName);
  assert.equal(gateResult.graphVersion, docsArtifact.graphVersion);
  assert.equal(gateResult.redactionRequired, true);
  assert.equal(gateResult.auditRequired, true);
  assert.equal(gateResult.writesArtifacts, false);
  assert.equal(gateResult.writesLogs, false);
  assert.equal(gateResult.writesDocs, false);
  assert.equal(gateResult.writesRepo, false);
  assert.equal(gateResult.runtimeArtifactWriteEnabled, false);
  assert.equal(gateResult.externalTelemetry, false);
  assert.equal(gateResult.externalTelemetryEnabled, false);
  assert.equal(gateResult.externalDispatchEnabled, false);
  assert.equal(gateResult.publishEnabled, false);
  assert.equal(gateResult.siteAdapterInvocation, false);
  assert.equal(gateResult.downloaderInvocation, false);
  assert.equal(gateResult.sessionMaterialization, false);
  assert.equal(gateResult.sessionViewMaterialized, false);
  assert.equal(gateResult.consumerResults.length, 1);
  assert.equal(consumerResult.accepted, true);
  assert.equal(consumerResult.consumerId, 'synthetic-docs-markdown-redaction-audit-gate-consumer');
  assert.equal(consumerResult.artifactFamily, 'site-capability-graph-docs-markdown');
  assert.equal(consumerResult.queryName, docsArtifact.queryName);
  assert.equal(consumerResult.graphVersion, docsArtifact.graphVersion);
  assert.equal(consumerResult.redactionRequired, true);
  assert.equal(consumerResult.externalTelemetryEnabled ?? false, false);
  assert.equal(consumerResult.writesArtifacts ?? false, false);
  assert.equal(consumerResult.writesLogs ?? false, false);
  assert.equal(consumerResult.writesDocs ?? false, false);
  assert.equal(consumerResult.writesRepo ?? false, false);
  assert.equal(consumerResult.sessionMaterializationEnabled ?? false, false);
  assert.equal(consumerResult.downloaderInvocationEnabled ?? false, false);
  assert.equal(consumerResult.siteAdapterInvocationEnabled ?? false, false);
  assert.equal(assertNoFunctionValues({ gateResult, consumerResult, descriptors }), true);
  assert.doesNotMatch(
    JSON.stringify({ gateResult, consumerResult, descriptors }),
    /function|synthetic-secret-value|Authorization|Bearer|cookie|csrf|sessionId|browserProfile/iu,
  );
  assert.doesNotMatch(
    JSON.stringify({ gateResult, consumerResult, descriptors }),
    /"sessionView"\s*:|"downloadPolicy"\s*:|"downloader"\s*:|"siteAdapter"\s*:|"runtimePayload"\s*:/u,
  );
});

test('graph-derived artifact consumer dispatch redaction audit gate rejects missing mutated or incompatible audit', async () => {
  const { create: createRegistry } = loadGraphDerivedArtifactConsumerRegistryApi();
  const { create: createConsumer } = loadGraphDocsMarkdownArtifactRegistryConsumerApi();
  const { dispatch: dispatchWithRedactionAuditGate } =
    loadGraphDerivedArtifactConsumerDispatchRedactionGateApi();
  const graph = await readMinimalGraphFixture();
  const summary = generateGraphDocsSummary(graph);
  const docsArtifact = createGraphDocsMarkdownArtifact(summary);
  const prepared = prepareGraphDerivedArtifactWrite(docsArtifact);
  const registry = createRegistry();
  registerGraphDerivedArtifactConsumer(registry, createConsumer({
    consumerId: 'synthetic-docs-markdown-redaction-audit-gate-audit-reject-consumer',
  }));

  for (const { name, redactionAuditAttachment, pattern } of [
    {
      name: 'missingAudit',
      redactionAuditAttachment: undefined,
      pattern: /RedactionAuditAttachment|object|redaction audit/i,
    },
    {
      name: 'artifactFamily',
      redactionAuditAttachment: {
        ...prepared.redactionAuditAttachment,
        artifactFamily: 'site-capability-graph-mutated-family',
      },
      pattern: /artifactFamily.*match|redaction audit/i,
    },
    {
      name: 'sourceArtifactQueryName',
      redactionAuditAttachment: {
        ...prepared.redactionAuditAttachment,
        sourceArtifactQueryName: 'synthetic-mutated-query',
      },
      pattern: /sourceArtifactQueryName.*match|queryName/i,
    },
    {
      name: 'redactionRequired',
      redactionAuditAttachment: {
        ...prepared.redactionAuditAttachment,
        redactionRequired: false,
      },
      pattern: /redactionRequired.*true|redaction/i,
    },
    {
      name: 'auditRequired',
      redactionAuditAttachment: {
        ...prepared.redactionAuditAttachment,
        auditRequired: false,
      },
      pattern: /auditRequired.*true|audit/i,
    },
  ]) {
    const message = await captureRejectedMessage(() => dispatchWithRedactionAuditGate({
      consumerRegistry: registry,
      artifact: docsArtifact,
      redactionAuditAttachment,
    }));
    assert.match(message, pattern, name);
    assert.doesNotMatch(message, /synthetic-secret-value/u, name);
  }
});

