test('docs markdown runtime write-path guard consumes redaction audit attachment while disabled', async () => {
  const graph = await readMinimalGraphFixture();
  const summary = generateGraphDocsSummary(graph);
  const docsArtifact = createGraphDocsMarkdownArtifact(summary);
  const { dir } = await createTempArtifactPaths();
  const placement = createGraphDerivedArtifactPlacement({
    outputDir: dir,
    runId: 'synthetic-run-001',
    artifactFamily: 'site-capability-graph-docs-markdown',
    artifactName: 'graph-docs-markdown',
  });
  const writeResult = await writeGraphDerivedArtifactPair(docsArtifact, placement);

  const guard = createGraphDocsMarkdownRuntimeWritePathIntegrationGuard(
    docsArtifact,
    writeResult.redactionAuditAttachment,
  );
  const item = guard.items[0];

  assert.equal(assertGraphDocsMarkdownRuntimeWritePathIntegrationGuardCompatibility(guard), true);
  assert.equal(
    guard.artifactFamily,
    'site-capability-graph-docs-markdown-runtime-write-path-integration-guard',
  );
  assert.equal(guard.redactionRequired, true);
  assert.equal(item.guardMode, 'disabled-runtime-write-path-integration');
  assert.equal(item.integrationEnabled, false);
  assert.equal(item.docsWriteEnabled, false);
  assert.equal(item.repoWriteEnabled, false);
  assert.equal(item.runtimeArtifactWriteEnabled, false);
  assert.equal(item.result, 'blocked');
  assert.equal(item.reasonCode, 'graph-runtime-consumer-disabled');
  assert.equal(item.redactionRequiredBeforeWrite, true);
  assert.equal(item.layerConsumerRequired, true);
  assert.deepEqual(item.sourceArtifact, {
    queryName: 'renderGraphDocsSummaryMarkdown',
    artifactFamily: 'site-capability-graph-docs-markdown',
  });
  assert.equal(
    item.sourceRedactionAuditAttachment.attachmentKind,
    'site-capability-graph-redaction-audit-attachment',
  );
  assert.equal(item.sourceRedactionAuditAttachment.writeOrder, 'audit-before-artifact');
  assert.equal(item.sourceRedactionAuditAttachment.auditSchemaVersion, 1);
  assert.equal(item.sourceRedactionAuditAttachment.redactionRequired, true);
  assert.equal(item.sourceRedactionAuditAttachment.artifactPath, undefined);
  assert.equal(item.sourceRedactionAuditAttachment.auditPath, undefined);
  assert.equal(assertNoForbiddenPatterns(guard), true);
});

