test('graph artifact writer can prepare the redacted pair without filesystem writes', async () => {
  const graph = await readMinimalGraphFixture();
  const summary = generateGraphDocsSummary(graph);

  const prepared = prepareGraphDerivedArtifactWrite(summary);

  assert.equal(prepared.schemaVersion, 1);
  assert.equal(prepared.artifactFamily, 'site-capability-graph-docs');
  assert.equal(prepared.redactionRequired, true);
  assert.equal(JSON.parse(prepared.artifactJson).redactionRequired, true);
  assert.equal(JSON.parse(prepared.auditJson).schemaVersion, 1);
  assert.equal(
    assertGraphDerivedArtifactRedactionAuditAttachmentCompatible(prepared.redactionAuditAttachment),
    true,
  );
  assert.equal(prepared.redactionAuditAttachment.writeOrder, 'prepared-no-filesystem-write');
  assert.equal(prepared.redactionAuditAttachment.auditRequired, true);
  assert.equal(prepared.redactionAuditAttachment.artifactRedactionRequired, true);
  assert.equal(prepared.redactionAuditAttachment.auditSchemaVersion, 1);
  assert.equal(prepared.redactionAuditAttachment.auditFindingsCount, 0);
  assert.equal(assertNoForbiddenPatterns(prepared.artifactJson), true);
  assert.equal(assertNoForbiddenPatterns(prepared.auditJson), true);
});

test('graph artifact placement creates a contained run artifact pair path for writer use', async () => {
  const graph = await readMinimalGraphFixture();
  const summary = generateGraphDocsSummary(graph);
  const { dir } = await createTempArtifactPaths();

  const placement = createGraphDerivedArtifactPlacement({
    outputDir: dir,
    runId: 'synthetic-run-001',
    artifactFamily: 'site-capability-graph-docs',
    artifactName: 'graph-docs-summary',
  });

  assert.equal(placement.schemaVersion, 1);
  assert.equal(placement.placementKind, 'site-capability-graph-derived-artifact-pair');
  assert.equal(placement.outputDir, path.resolve(dir));
  assert.equal(placement.artifactFileName, path.join(
    'synthetic-run-001',
    'site-capability-graph-docs',
    'graph-docs-summary.json',
  ));
  assert.equal(placement.auditFileName, path.join(
    'synthetic-run-001',
    'site-capability-graph-docs',
    'graph-docs-summary.redaction-audit.json',
  ));
  assert.equal(path.dirname(placement.artifactPath), path.dirname(placement.auditPath));
  assert.equal(assertNoForbiddenPatterns(placement), true);

  const result = await writeGraphDerivedArtifactPair(summary, placement);

  assert.equal(result.artifactPath, placement.artifactPath);
  assert.equal(result.auditPath, placement.auditPath);
  assert.equal(await pathExists(placement.artifactPath), true);
  assert.equal(await pathExists(placement.auditPath), true);
});

test('graph artifact writer redacts sensitive artifact node fields before persistence and records audit evidence', async () => {
  const rawSensitiveValue = 'synthetic-sensitive-raw-session-lease-value';
  const artifactNode = {
    schemaVersion: 1,
    id: 'artifact:synthetic-security-redaction-probe',
    type: 'ArtifactNode',
    artifactFamily: 'site-capability-graph-security-redaction-probe',
    redactionRequired: true,
    schemaRef: 'schema:synthetic-security-redaction-probe',
    writeGuard: 'SecurityGuard/Redaction',
    auditRequired: true,
    rawSessionLease: rawSensitiveValue,
  };
  const { dir } = await createTempArtifactPaths();
  const placement = createGraphDerivedArtifactPlacement({
    outputDir: dir,
    runId: 'synthetic-run-001',
    artifactFamily: 'site-capability-graph-security-redaction-probe',
    artifactName: 'artifact-node-redaction-probe',
  });

  const result = await writeGraphDerivedArtifactPair(artifactNode, placement);
  const artifactJson = await readFile(placement.artifactPath, 'utf8');
  const auditJson = await readFile(placement.auditPath, 'utf8');
  const persistedArtifact = JSON.parse(artifactJson);
  const persistedAudit = JSON.parse(auditJson);
  const renderedResult = JSON.stringify(result);

  assert.equal(persistedArtifact.rawSessionLease, REDACTION_PLACEHOLDER);
  assert.equal(persistedArtifact.writeGuard, 'SecurityGuard/Redaction');
  assert.equal(persistedArtifact.auditRequired, true);
  assert.equal(persistedAudit.redactedPaths.includes('rawSessionLease'), true);
  assert.equal(
    persistedAudit.redactions.some((entry) => (
      entry.path === 'rawSessionLease'
        && entry.reason === 'sensitive-field-name'
    )),
    true,
  );
  assert.equal(result.audit.redactions.length, persistedAudit.redactions.length);
  assert.equal(result.redactionAuditAttachment.writeOrder, 'audit-before-artifact');
  assert.equal(result.redactionAuditAttachment.auditRedactionsCount, persistedAudit.redactions.length);
  assert.equal(result.redactionAuditAttachment.artifactRedactionRequired, true);
  assert.equal(await pathExists(placement.artifactPath), true);
  assert.equal(await pathExists(placement.auditPath), true);
  assert.equal(assertNoForbiddenPatterns(artifactJson), true);
  assert.equal(assertNoForbiddenPatterns(auditJson), true);
  assert.doesNotMatch(artifactJson, new RegExp(rawSensitiveValue, 'u'));
  assert.doesNotMatch(auditJson, new RegExp(rawSensitiveValue, 'u'));
  assert.doesNotMatch(renderedResult, new RegExp(rawSensitiveValue, 'u'));
});

test('graph artifact placement rejects unsafe run, family, or artifact name segments', () => {
  const outputDir = path.join(os.tmpdir(), 'site-capability-graph-placement');
  const unsafeOptions = [
    { runId: '' },
    { runId: '..' },
    { runId: 'synthetic\\run' },
    { runId: 'Synthetic-Run' },
    { artifactFamily: 'download-artifacts' },
    { artifactFamily: 'site-capability-graph-docs/unsafe' },
    { artifactName: '..\\graph-docs-summary' },
    { artifactName: 'graph_docs_summary' },
  ];

  for (const option of unsafeOptions) {
    assert.throws(
      () => createGraphDerivedArtifactPlacement({
        outputDir,
        runId: 'synthetic-run-001',
        artifactFamily: 'site-capability-graph-docs',
        artifactName: 'graph-docs-summary',
        ...option,
      }),
      /required|lowercase graph artifact path segment|site-capability-graph prefix/u,
    );
  }
});

test('graph artifact writer fails closed before writing unsupported or unredacted descriptors', async () => {
  const graph = await readMinimalGraphFixture();
  const unredactedSummary = generateGraphDocsSummary(graph);
  unredactedSummary.redactionRequired = false;
  const unsupported = {
    schemaVersion: 1,
    graphVersion: 'synthetic-graph-v1',
    redactionRequired: true,
    payload: [],
  };

  for (const artifact of [unredactedSummary, unsupported]) {
    const {
      dir,
      artifactFileName,
      auditFileName,
      artifactPath,
      auditPath,
    } = await createTempArtifactPaths();
    await assert.rejects(
      () => writeGraphDerivedArtifactPair(artifact, {
        outputDir: dir,
        artifactFileName,
        auditFileName,
      }),
      /redactionRequired=true|Unsupported graph-derived artifact type/u,
    );
    assert.equal(await pathExists(artifactPath), false);
    assert.equal(await pathExists(auditPath), false);
  }
});

