test('docs markdown runtime write-path guard rejects enabled runtime products and mutated audit attachments', async () => {
  const graph = await readMinimalGraphFixture();
  const summary = generateGraphDocsSummary(graph);
  const docsArtifact = createGraphDocsMarkdownArtifact(summary);
  const { dir } = await createTempArtifactPaths();
  const placement = createGraphDerivedArtifactPlacement({
    outputDir: dir,
    runId: 'synthetic-run-001',
    artifactFamily: 'site-capability-graph-docs-markdown',
    artifactName: 'graph-docs-markdown',
  });
  const writeResult = await writeGraphDerivedArtifactPair(docsArtifact, placement);

  for (const options of [
    { integrationEnabled: true },
    { docsWriteEnabled: true },
    { runtimeArtifactWriteEnabled: true },
    { sessionView: { accountId: 'synthetic-user' } },
    { downloadPolicy: { mode: 'synthetic' } },
    { publishEnabled: true },
  ]) {
    assert.throws(
      () => createGraphDocsMarkdownRuntimeWritePathIntegrationGuard(
        docsArtifact,
        writeResult.redactionAuditAttachment,
        options,
      ),
      /must be false|must keep runtime write-path products disabled/u,
    );
  }

  const mutatedAttachment = {
    ...writeResult.redactionAuditAttachment,
    auditRequired: false,
  };
  assert.throws(
    () => createGraphDocsMarkdownRuntimeWritePathIntegrationGuard(docsArtifact, mutatedAttachment),
    /auditRequired must be true/u,
  );
});

